/**
 * The main Code Input Card — headline component of the landing view.
 *
 * Contains the code textarea, language + model pill selectors, and the
 * Explain Code CTA. It is intentionally self-contained: the parent passes
 * down the current values and a submit callback and receives nothing else.
 */

import React, { useMemo } from 'react';
import { Sparkles, Code2, Cpu } from 'lucide-react';
import { Button } from '../shared/ui';
import { PillDropdown } from '../shared/PillDropdown';
import { LANGUAGES, detectLanguage } from '../../lib/languages';
import type { ModelOption } from '../../lib/types';

interface Props {
  code: string;
  onCodeChange: (v: string) => void;
  language: string;
  onLanguageChange: (v: string) => void;
  modelKey: string;
  onModelChange: (v: string) => void;
  models: ModelOption[];
  onSubmit: () => void;
  loading: boolean;
  inlineError: string | null;
}

export const CodeInputCard: React.FC<Props> = ({
  code,
  onCodeChange,
  language,
  onLanguageChange,
  modelKey,
  onModelChange,
  models,
  onSubmit,
  loading,
  inlineError,
}) => {
  const langOptions = useMemo(
    () => LANGUAGES.map((l) => ({ key: l.key, label: l.label })),
    [],
  );

  const modelOptions = useMemo(
    () =>
      models.map((m) => ({
        key: m.key,
        label: m.display_name,
        sublabel: m.model_id,
      })),
    [models],
  );

  // When the user pastes new code, auto-detect language once, but never
  // overwrite an explicit user choice from the dropdown.
  const handleCodeChange = (val: string) => {
    onCodeChange(val);
    if (!code && val) {
      const guessed = detectLanguage(val);
      if (guessed) onLanguageChange(guessed);
    }
  };

  const canSubmit = code.trim().length > 0 && !loading;

  return (
    <div className="relative mx-auto w-full max-w-4xl px-md md:px-lg pb-xl" data-testid="code-input-card">
      <div className="glass rounded-card p-md md:p-lg shadow-2xl shadow-black/40">
        <label htmlFor="code-input" className="sr-only">
          Paste code to explain
        </label>
        <textarea
          id="code-input"
          data-testid="code-textarea"
          value={code}
          onChange={(e) => handleCodeChange(e.target.value)}
          placeholder="Paste the code you want explained…"
          spellCheck={false}
          className="w-full resize-none bg-transparent text-ink-primary placeholder:text-ink-muted font-mono text-sm md:text-[15px] leading-relaxed outline-none min-h-[200px] md:min-h-[240px]"
          rows={10}
        />

        {inlineError && (
          <div
            className="mt-sm text-sm text-red-300"
            role="alert"
            data-testid="code-input-error"
          >
            {inlineError}
          </div>
        )}

        <div className="mt-lg flex flex-wrap items-center justify-between gap-sm border-t border-border-subtle pt-md">
          <div className="flex flex-wrap items-center gap-sm">
            <PillDropdown
              icon={<Code2 size={14} />}
              ariaLabel="Language"
              value={language}
              options={langOptions}
              onChange={onLanguageChange}
              testId="language-pill"
            />
            <PillDropdown
              icon={<Cpu size={14} />}
              ariaLabel="Model"
              value={modelKey}
              options={modelOptions}
              onChange={onModelChange}
              testId="model-pill"
            />
          </div>

          <Button
            onClick={onSubmit}
            loading={loading}
            disabled={!canSubmit}
            data-testid="explain-submit-btn"
          >
            {!loading && <Sparkles size={16} />}
            {loading ? 'Explaining…' : 'Explain Code'}
          </Button>
        </div>
      </div>
    </div>
  );
};
